"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const lanes=[["Brief","A short orientation for this decision."],["Evidence","Two sources support the current direction."],["Next step","Send the small release for review."]];
export default function SectionLanePicker(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <nav className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]" aria-label="Section lane"><div className="relative grid grid-cols-3 gap-1 border-b border-[#ececee]">{lanes.map((lane,i)=><button type="button" aria-pressed={active===i} key={lane[0]} onClick={()=>setActive(i)} className="min-h-11 px-1 text-xs font-black text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{lane[0]}</button>)}<motion.i aria-hidden className="absolute bottom-[-1px] h-1 w-1/3 rounded-full bg-[#39c6df]" animate={{left:`${active*33.333}%`}} transition={reduced?{duration:0}:{type:"spring",stiffness:330,damping:27}}/></div><motion.p key={active} initial={{opacity:0,y:4}} animate={{opacity:1,y:0}} transition={{duration:reduced?.12:.15}} className="mt-5 text-sm text-[#4a4a4f]">{lanes[active][1]}</motion.p><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">{lanes[active][0]} section selected.</p></nav>}
